// Fonction pour corriger le texte mal encodé (UTF-8 lu comme Latin-1)
function fixEncoding(str) {
    if (!str || typeof str !== 'string') return str;

    try {
        // Étape 1: Convertir la chaîne mal affichée en Buffer (en utilisant Latin-1)
        const buffer = Buffer.from(str, 'latin1');

        // Étape 2: Re-interpréter ce Buffer en UTF-8
        return buffer.toString('utf-8');
    } catch (e) {
        return str;
    }
}

// Appliquer la correction sur tous les champs texte de votre item
for (const item of items) {
    for (const [key, value] of Object.entries(item.json)) {
        if (typeof value === 'string') {
            // Ne corriger que si le texte contient des signes suspects (Ù, Å, etc.)
            if (/[ÙÅÊËÈÍÎÏ]/.test(value)) {
                item.json[key] = fixEncoding(value);
            }
        }
    }
}

return items;

for (const item of items) {
    if (item.json.textPlain) {
        const text = item.json.textPlain;

        // Trouver la position de "De : ai@jbel-annour.ma"
        const index = text.indexOf("De : ai@jbel-annour.ma");

        if (index !== -1) {
            // Extraire le texte avant
            item.json.text_before_de = text.substring(0, index).trim();

        } else {
            // Si pas trouvé, garder tout le texte
            item.json.text_before_de = text;
        }
    }
}

return items;

// Texte d'entrée
const inputText = $json.subject;

// Expression régulière pour extraire les variables
const regex = /BC(\d{6,7})\/T(\d{4,5})\/(\d+)/;
const match = inputText.match(regex);

if (match) {
    // Extraction des trois variables
    const variable1 = match[1]; // 190245
    const variable2 = match[2]; // 2024  
    const variable3 = match[3]; // 1

    // Création de l'objet résultat
    const result = {
        numero_commande: 'BC' + variable1,
        tier: 'T' + variable2,
        id: variable3
    };

    console.log("Variables extraites :", result);
    return result;
} else {
    console.log("Aucune correspondance trouvée");
    return null;
}
